import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';
import { Plus, AlertTriangle, Search } from 'lucide-react';

const API = process.env.REACT_APP_API_URL || 'http://localhost:5000';

export default function CivilianDashboard() {
  const { user } = useAuth();
  const [reports, setReports] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search,  setSearch]  = useState('');
  const [filter,  setFilter]  = useState('');

  useEffect(() => {
    axios.get('/api/reports').then(r => { setReports(r.data); setLoading(false); });
  }, []);

  const filtered = reports.filter(r => {
    const ms = !search || r.title.toLowerCase().includes(search.toLowerCase()) || r.location_text.toLowerCase().includes(search.toLowerCase());
    const mf = !filter || r.status === filter;
    return ms && mf;
  });

  const counts = {
    total:    reports.length,
    pending:  reports.filter(r => r.status === 'pending').length,
    active:   reports.filter(r => ['under_review','in_progress'].includes(r.status)).length,
    resolved: reports.filter(r => r.status === 'resolved').length,
  };

  return (
    <div className="page-container">
      <div style={{ display:'flex', alignItems:'flex-start', justifyContent:'space-between', marginBottom:28, flexWrap:'wrap', gap:14 }}>
        <div>
          <h1 style={{ fontSize:24, marginBottom:4 }}>My Reports</h1>
          <p style={{ color:'var(--text-muted)', fontSize:14 }}>Welcome, {user.name}</p>
        </div>
        <Link to="/submit" className="btn btn-primary"><Plus size={16}/> Report Hazard</Link>
      </div>

      <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fit,minmax(150px,1fr))', gap:14, marginBottom:28 }}>
        {[
          { label:'Total',      value:counts.total,    color:'var(--text)',   bg:'var(--bg-card)' },
          { label:'Pending',    value:counts.pending,  color:'var(--yellow)', bg:'var(--yellow-dim)' },
          { label:'In Progress',value:counts.active,   color:'var(--accent)', bg:'var(--accent-glow)' },
          { label:'Resolved',   value:counts.resolved, color:'var(--green)',  bg:'var(--green-dim)' },
        ].map(s => (
          <div key={s.label} style={{ background:s.bg, border:'1px solid var(--border)', borderRadius:12, padding:'16px 18px' }}>
            <div style={{ fontSize:26, fontWeight:800, color:s.color, fontFamily:'var(--font-display)' }}>{s.value}</div>
            <div style={{ fontSize:12, color:'var(--text-muted)', marginTop:2 }}>{s.label}</div>
          </div>
        ))}
      </div>

      <div style={{ display:'flex', gap:10, marginBottom:20, flexWrap:'wrap' }}>
        <div style={{ position:'relative', flex:1, minWidth:200 }}>
          <Search size={15} style={{ position:'absolute', left:12, top:'50%', transform:'translateY(-50%)', color:'var(--text-faint)' }}/>
          <input className="form-input" placeholder="Search reports…" style={{ paddingLeft:36 }}
            value={search} onChange={e => setSearch(e.target.value)}/>
        </div>
        <select className="form-input" style={{ width:180 }} value={filter} onChange={e => setFilter(e.target.value)}>
          <option value="">All Status</option>
          <option value="pending">Pending</option>
          <option value="under_review">Under Review</option>
          <option value="in_progress">In Progress</option>
          <option value="resolved">Resolved</option>
          <option value="rejected">Rejected</option>
        </select>
      </div>

      {loading ? (
        <div style={{ textAlign:'center', padding:60, color:'var(--text-muted)' }}>Loading…</div>
      ) : filtered.length === 0 ? (
        <div style={{ textAlign:'center', padding:60 }}>
          <AlertTriangle size={40} color="var(--text-faint)" style={{ marginBottom:12 }}/>
          <p style={{ color:'var(--text-muted)' }}>
            {reports.length === 0 ? 'No reports yet. Report your first hazard!' : 'No reports match your search.'}
          </p>
          {reports.length === 0 && <Link to="/submit" className="btn btn-primary" style={{ marginTop:16 }}><Plus size={15}/> Report Hazard</Link>}
        </div>
      ) : (
        <div style={{ display:'flex', flexDirection:'column', gap:12 }}>
          {filtered.map(r => (
            <Link key={r.id} to={`/reports/${r.id}`} style={{ display:'block' }}>
              <div className="card" style={{ display:'flex', gap:16, alignItems:'flex-start', cursor:'pointer' }}
                onMouseEnter={e => e.currentTarget.style.borderColor = 'var(--border-light)'}
                onMouseLeave={e => e.currentTarget.style.borderColor = 'var(--border)'}>
                {r.image_url && (
                  <img src={`${API}${r.image_url}`} alt="Report"
                    style={{ width:80, height:80, objectFit:'cover', borderRadius:8, flexShrink:0 }}/>
                )}
                <div style={{ flex:1, minWidth:0 }}>
                  <div style={{ display:'flex', justifyContent:'space-between', flexWrap:'wrap', gap:8, marginBottom:6 }}>
                    <h4 style={{ fontSize:15, fontWeight:600 }}>{r.title}</h4>
                    <div style={{ display:'flex', gap:6 }}>
                      <span className={`badge badge-${r.severity}`}>{r.severity}</span>
                      <span className={`badge badge-${r.status}`}>{r.status.replace('_',' ')}</span>
                    </div>
                  </div>
                  <p style={{ fontSize:13, color:'var(--text-muted)', marginBottom:6 }}>📍 {r.location_text}</p>
                  <div style={{ fontSize:12, color:'var(--text-faint)', display:'flex', gap:10 }}>
                    <span>{r.hazard_type.replace('_',' ')}</span>
                    <span>•</span>
                    <span>{new Date(r.created_at).toLocaleDateString()}</span>
                  </div>
                </div>
              </div>
            </Link>
          ))}
        </div>
      )}
    </div>
  );
}
